func CalculateDiscount(originalPrice float64, discountRate float64) (float64, error) {
	if originalPrice < 0 {
		return 0, errors.New("original_price cannot be negative")
	}

	if discountRate < 0 {
		return 0, errors.New("discount_rate cannot be negative")
	}

	if discountRate > 1 {
		return 0, errors.New("discount_rate cannot be greater than 1")
	}

	discountedPrice := originalPrice * (1 - float64(discountRate)/100)
	return discountedPrice, nil
}

