	discountRate := 20.0

	discountedPrice, err := CalculateDiscount(originalPrice, discountRate)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Discounted price: %f\n", discountedPrice)
	}
