fn string_compression(s: String) -> String {
    if s.is_empty() {
        return s;
    }

    let mut result = String::new();
    let mut count = 1;
    let mut prev_char = s.chars().next().unwrap();

    for char in s.chars().skip(1) {
        if char == prev_char {
            count += 1;
        } else {
            result.push_str(&format!("{}{}", prev_char, count));
            prev_char = char;
            count = 1;
        }
    }

    result.push_str(&format!("{}{}", prev_char, count));
    if result.len() >= s.len() {
        s
    } else {
        result
    }
