const (
    shortURLLength = 6
)

type URLShortener struct {
    urlMap map[string]string
}

func NewURLShortener() *URLShortener {
    return &URLShortener{
        urlMap: make(map[string]string),
    }
}

func (s *URLShortener) StoreURL(originalURL string) (string, error) {
    if !isValidURL(originalURL) {
        return "", errors.New("invalid URL")
    }

    shortURL := generateShortURL()
    s.urlMap[shortURL] = originalURL

    return shortURL, nil
}

func (s *URLShortener) RetrieveURL(shortURL string) (string, error) {
    originalURL, ok := s.urlMap[shortURL]
    if !ok {
        return "", errors.New("short URL not found")
    }

    return originalURL, nil
}

func isValidURL(url string) bool {
    _, err := http.Get(url)
    return err == nil
}

func generateShortURL() string {
    start := time.Now().UnixNano()
    shortURL := strings.Format("%06d", start)
    return shortURL
}

func main() {
    shortener := NewURLShortener()
    shortURL, err := shortener.StoreURL("https://www.example.com/very/long/url")
    if err != nil {
        panic(err)
    }
    fmt.Printf("Short URL: %s\n", shortURL)

    originalURL, err := shortener.RetrieveURL(shortURL)
    if err != nil {
        panic(err)
    }
    fmt.Printf("Original URL: %s\n", originalURL)
}
