    fn load_from_file(path: &str) -> Result<Config, Error> {
        // Attempt to read the file.
        let mut file = File::open(path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;

        // Parse the configuration from the JSON string.
        let config: Config = serde_json::from_str(&contents)?;

        Ok(config)
    }
}

pub fn load_configuration(path: &str) -> Result<serde_json::Value, std::io::Error> {
    // Load the configuration from the file.
    let config = Config::load_from_file(path)?;

    // Return the configuration as a JSON value.
    Ok(serde_json::to_value(config)?)
