// ProcessTransaction converts the provided amount from one currency to another.
func ProcessTransaction(amount float64, sourceCurrency, targetCurrency string) (float64, error) {
	// Define the predefined currency conversion rates.
	rates := []CurrencyRate{
		{"USD", "JPY", 114.39},
		{"EUR", "JPY", 128.66},
	}

	// Find the conversion rate for the source currency.
	for _, rate := range rates {
		if rate.Source == sourceCurrency {
