			for _, existingRate := range rates {
				if existingRate.Target == targetCurrency && existingRate.Source == rate.Source {
					return amount*existingRate.Amount, nil
				}
			}
			// If the target currency is not supported, return an error.
			return 0, errors.New("unsupported currency")
